mapper.select:
SELECT * FROM points_record

    AND student_id = #{studentId}
    AND type = #{type}

ORDER BY operate_time DESC

mapper.update:
UPDATE points_record
SET student_id=#{studentId}, record_id=#{recordId}, points=#{points}, type=#{type}, balance=#{balance}, operator_id=#{operatorId}, operate_time=#{operateTime}, remark=#{remark}
WHERE id=#{id}

mapper.select:
SELECT pr.* FROM points_record pr
INNER JOIN user u ON pr.student_id = u.id

    u.parent_id = #{parentId}

        AND pr.student_id = #{studentId}


        AND pr.type = #{type}


ORDER BY pr.operate_time DESC

SELECT * FROM points_record

    AND student_id = #{studentId}
    AND type = #{type}
    AND DATE(operate_time) = #{date}

ORDER BY operate_time DESC

SELECT pr.* FROM points_record pr
INNER JOIN user u ON pr.student_id = u.id

    u.parent_id = #{parentId}

        AND pr.student_id = #{studentId}


        AND pr.type = #{type}


