SELECT pr.*, s.real_name as student_name, o.real_name as operator_name FROM points_record pr LEFT JOIN user s ON pr.student_id = s.id LEFT JOIN user o ON pr.operator_id = o.id
AND pr.student_id = #{studentId} AND pr.type = #{type}
ORDER BY pr.operate_time DESC

